42	
43	package fifo is
44	
45	  -- Minimal FIFO with single clock to decouple enable domains.
46	  component fifo_glue
47	    generic (
48	      D_BITS : positive                   -- Data Width
49	    );
50	    port (
51	      -- Control
52	      clk : in std_logic;                 -- Clock
53	      rst : in std_logic;                 -- Synchronous Reset
54	
55	      -- Input
56	      put : in  std_logic;                            -- Put Value
57	      di  : in  std_logic_vector(D_BITS - 1 downto 0);  -- Data Input
58	      ful : out std_logic;                            -- Full
59	
60	      -- Output
61	      vld : out std_logic;                            -- Data Available
62	      do  : out std_logic_vector(D_BITS - 1 downto 0);  -- Data Output
63	      got : in  std_logic                             -- Data Consumed
64	    );
65	  end component;
66	
67	  -- Minimal Local-Link-FIFO with single clock and first-word-fall-through mode.
68	  component fifo_ll_glue
69	    generic (
70	      D_BITS          : positive;
71	      FRAME_USER_BITS : natural;
72	      REGISTER_PATH   : boolean
73	      );
74	    port (
75	      clk   : in std_logic;
76	      reset : in std_logic;
77	
78	      -- in port
79	      sof_in        : in  std_logic;
80	      data_in       : in  std_logic_vector(D_BITS downto 1);
81	      frame_data_in : in  std_logic_vector(imax(1, FRAME_USER_BITS) downto 1);
82	      eof_in        : in  std_logic;
83	      src_rdy_in    : in  std_logic;
84	      dst_rdy_in    : out std_logic;
85	
86	      -- out port
87	      sof_out        : out std_logic;
88	      data_out       : out std_logic_vector(D_BITS downto 1);
89	      frame_data_out : out std_logic_vector(imax(1, FRAME_USER_BITS) downto 1);
90	      eof_out        : out std_logic;
91	      src_rdy_out    : out std_logic;
92	      dst_rdy_out    : in  std_logic
93	      );
94	  end component;
95	
96	  -- Simple FIFO backed by a shift register.
97	  component fifo_shift
98	    generic (
99	      D_BITS    : positive;               -- Data Width
100	      MIN_DEPTH : positive                -- Minimum FIFO Size in Words
101	    );
102	    port (
103	      -- Global Control
104	      clk : in std_logic;
105	      rst : in std_logic;
106	
107	      -- Writing Interface
108	      put : in  std_logic;                            -- Write Request
109	      din : in  std_logic_vector(D_BITS - 1 downto 0);  -- Input Data
110	      ful : out std_logic;                            -- Capacity Exhausted
111	
112	      -- Reading Interface
113	      got  : in  std_logic;                            -- Read Done Strobe
114	      dout : out std_logic_vector(D_BITS - 1 downto 0);  -- Output Data
115	      vld  : out std_logic                             -- Data Valid
116	    );
117	  end component;
118	
119	  -- Full-fledged FIFO with single clock domain using on-chip RAM.
120	  component fifo_cc_got
121	    generic (
122	      D_BITS         : positive;          -- Data Width
123	      MIN_DEPTH      : positive;          -- Minimum FIFO Depth
124	      DATA_REG       : boolean := false;  -- Store Data Content in Registers
125	      STATE_REG      : boolean := false;  -- Registered Full/Empty Indicators
126	      OUTPUT_REG     : boolean := false;  -- Registered FIFO Output
127	      ESTATE_WR_BITS : natural := 0;      -- Empty State Bits
128	      FSTATE_RD_BITS : natural := 0       -- Full State Bits
129	    );
130	    port (
131	      -- Global Reset and Clock
132	      rst, clk : in  std_logic;
133	
134	      -- Writing Interface
135	      put       : in  std_logic;                            -- Write Request
136	      din       : in  std_logic_vector(D_BITS - 1 downto 0);  -- Input Data
137	      full      : out std_logic;
138	      estate_wr : out std_logic_vector(imax(0, ESTATE_WR_BITS - 1) downto 0);
139	
140	      -- Reading Interface
141	      got       : in  std_logic;                            -- Read Completed
142	      dout      : out std_logic_vector(D_BITS - 1 downto 0);  -- Output Data
143	      valid     : out std_logic;
144	      fstate_rd : out std_logic_vector(imax(0, FSTATE_RD_BITS - 1) downto 0)
145	    );
146	  end component;
147	
148	  component fifo_dc_got_sm
149	    generic (
150	      D_BITS    : positive;
151	      MIN_DEPTH : positive);
152	    port (
153	      clk_wr : in  std_logic;
154	      rst_wr : in  std_logic;
155	      put    : in  std_logic;
156	      din    : in  std_logic_vector(D_BITS - 1 downto 0);
157	      full   : out std_logic;
158	      clk_rd : in  std_logic;
159	      rst_rd : in  std_logic;
160	      got    : in  std_logic;
161	      valid  : out std_logic;
162	      dout   : out std_logic_vector(D_BITS - 1 downto 0));
163	  end component;
164	
165	  component fifo_ic_got
166	    generic (
167	      D_BITS         : positive;          -- Data Width
168	      MIN_DEPTH      : positive;          -- Minimum FIFO Depth
169	      DATA_REG       : boolean := false;  -- Store Data Content in Registers
170	      OUTPUT_REG     : boolean := false;  -- Registered FIFO Output
171	      ESTATE_WR_BITS : natural := 0;      -- Empty State Bits
172	      FSTATE_RD_BITS : natural := 0       -- Full State Bits
173	    );
174	    port (
175	      -- Write Interface
176	      clk_wr    : in  std_logic;
177	      rst_wr    : in  std_logic;
178	      put       : in  std_logic;
179	      din       : in  std_logic_vector(D_BITS - 1 downto 0);
180	      full      : out std_logic;
181	      estate_wr : out std_logic_vector(imax(ESTATE_WR_BITS - 1, 0) downto 0);
182	
183	      -- Read Interface
184	      clk_rd    : in  std_logic;
185	      rst_rd    : in  std_logic;
186	      got       : in  std_logic;
187	      valid     : out std_logic;
188	      dout      : out std_logic_vector(D_BITS - 1 downto 0);
189	      fstate_rd : out std_logic_vector(imax(FSTATE_RD_BITS - 1, 0) downto 0)
190	    );
191	  end component;
192	
193	  component fifo_cc_got_tempput
194	    generic (
195	      D_BITS         : positive;          -- Data Width
196	      MIN_DEPTH      : positive;          -- Minimum FIFO Depth
197	      DATA_REG       : boolean := false;  -- Store Data Content in Registers
198	      STATE_REG      : boolean := false;  -- Registered Full/Empty Indicators
199	      OUTPUT_REG     : boolean := false;  -- Registered FIFO Output
200	      ESTATE_WR_BITS : natural := 0;      -- Empty State Bits
201	      FSTATE_RD_BITS : natural := 0       -- Full State Bits
202	      );
203	    port (
204	      -- Global Reset and Clock
205	      rst, clk : in  std_logic;
206	
207	      -- Writing Interface
208	      put       : in  std_logic;                            -- Write Request
209	      din       : in  std_logic_vector(D_BITS - 1 downto 0);  -- Input Data
210	      full      : out std_logic;
211	      estate_wr : out std_logic_vector(imax(0, ESTATE_WR_BITS - 1) downto 0);
212	
213	      commit    : in  std_logic;
214	      rollback  : in  std_logic;
215	
216	      -- Reading Interface
217	      got       : in  std_logic;                            -- Read Completed
218	      dout      : out std_logic_vector(D_BITS - 1 downto 0);  -- Output Data
219	      valid     : out std_logic;
220	      fstate_rd : out std_logic_vector(imax(0, FSTATE_RD_BITS - 1) downto 0)
221	      );
222	  end component;
223	
224	  component fifo_cc_got_tempgot is
225	    generic (
226	      D_BITS         : positive;          -- Data Width
227	      MIN_DEPTH      : positive;          -- Minimum FIFO Depth
228	      DATA_REG       : boolean := false;  -- Store Data Content in Registers
229	      STATE_REG      : boolean := false;  -- Registered Full/Empty Indicators
230	      OUTPUT_REG     : boolean := false;  -- Registered FIFO Output
231	      ESTATE_WR_BITS : natural := 0;      -- Empty State Bits
232	      FSTATE_RD_BITS : natural := 0       -- Full State Bits
233	    );
234	    port (
235	      -- Global Reset and Clock
236	      rst, clk : in  std_logic;
237	
238	      -- Writing Interface
239	      put       : in  std_logic;                            -- Write Request
240	      din       : in  std_logic_vector(D_BITS - 1 downto 0);  -- Input Data
241	      full      : out std_logic;
242	      estate_wr : out std_logic_vector(imax(0, ESTATE_WR_BITS - 1) downto 0);
243	
244	      -- Reading Interface
245	      got       : in  std_logic;                            -- Read Completed
246	      dout      : out std_logic_vector(D_BITS - 1 downto 0);  -- Output Data
247	      valid     : out std_logic;
248	      fstate_rd : out std_logic_vector(imax(0, FSTATE_RD_BITS - 1) downto 0);
249	
250	      commit    : in  std_logic;
251	      rollback  : in  std_logic
252	    );
253	  end component;
254	
255		component fifo_ic_assembly is
256			generic (
257				D_BITS : positive;  								-- Data Width
258				A_BITS : positive;  								-- Address Bits
259				G_BITS : positive  									-- Generation Guard Bits
260			);
261			port (
262				-- Write Interface
263				clk_wr : in std_logic;
264				rst_wr : in std_logic;
265	
266				-- Only write addresses in the range [base, base+2**(A_BITS-G_BITS)) are
267				-- acceptable. This is equivalent to the test
268				--   tmp(A_BITS-1 downto A_BITS-G_BITS) = 0 where tmp = addr - base.
269				-- Writes performed outside the allowable range will assert the failure
270				-- indicator, which will stick until the next reset.
271				-- No write is to be performed before base turns zero (0) for the first
272				-- time.
273				base   : out std_logic_vector(A_BITS-1 downto 0);
274				failed : out std_logic;
275	
276				addr : in  std_logic_vector(A_BITS-1 downto 0);
277				din  : in  std_logic_vector(D_BITS-1 downto 0);
278				put  : in  std_logic;
279	
280				-- Read Interface
